/**
 * 本地存储键名
 */
const STORAGE_KEYS = {
  TASKS: 'todolist_tasks',
  CATEGORIES: 'todolist_categories',
  SETTINGS: 'todolist_settings'
};

/**
 * 存储服务 - 使用 localStorage
 */
class StorageService {
  /**
   * 保存数据到 localStorage
   */
  save(key, data) {
    try {
      const serialized = JSON.stringify(data);
      localStorage.setItem(key, serialized);
      return true;
    } catch (error) {
      console.error('Storage save error:', error);
      return false;
    }
  }

  /**
   * 从 localStorage 读取数据
   */
  load(key) {
    try {
      const data = localStorage.getItem(key);
      return data ? JSON.parse(data) : null;
    } catch (error) {
      console.error('Storage load error:', error);
      return null;
    }
  }

  /**
   * 删除数据
   */
  remove(key) {
    localStorage.removeItem(key);
  }

  /**
   * 清空所有数据
   */
  clear() {
    localStorage.clear();
  }

  /**
   * 获取所有任务
   */
  getTasks() {
    return this.load(STORAGE_KEYS.TASKS) || [];
  }

  /**
   * 保存所有任务
   */
  saveTasks(tasks) {
    return this.save(STORAGE_KEYS.TASKS, tasks);
  }

  /**
   * 获取所有分类
   */
  getCategories() {
    return this.load(STORAGE_KEYS.CATEGORIES) || [];
  }

  /**
   * 保存所有分类
   */
  saveCategories(categories) {
    return this.save(STORAGE_KEYS.CATEGORIES, categories);
  }

  /**
   * 获取设置
   */
  getSettings() {
    return this.load(STORAGE_KEYS.SETTINGS) || {};
  }

  /**
   * 保存设置
   */
  saveSettings(settings) {
    return this.save(STORAGE_KEYS.SETTINGS, settings);
  }
}

export const storageService = new StorageService();
