import { storageService } from './storage.js';
import { Task, TaskStatus, TaskPriority } from '../models/Task.js';

/**
 * 任务服务 - 处理业务逻辑
 */
class TaskService {
  constructor() {
    this.tasks = storageService.getTasks();
  }

  /**
   * 获取所有任务
   */
  getAllTasks() {
    return this.tasks.map(task => Task.fromJSON(task));
  }

  /**
   * 根据 ID 获取任务
   */
  getTaskById(id) {
    const taskData = this.tasks.find(t => t.id === id);
    return taskData ? Task.fromJSON(taskData) : null;
  }

  /**
   * 创建新任务
   */
  createTask(taskData) {
    const task = new Task(taskData);
    this.tasks.push(task.toJSON());
    this.persist();
    return task;
  }

  /**
   * 更新任务
   */
  updateTask(id, updates) {
    const index = this.tasks.findIndex(t => t.id === id);
    if (index === -1) {
      throw new Error(`Task with id ${id} not found`);
    }

    const task = Task.fromJSON(this.tasks[index]);
    task.update(updates);
    this.tasks[index] = task.toJSON();
    this.persist();
    return task;
  }

  /**
   * 删除任务
   */
  deleteTask(id) {
    const index = this.tasks.findIndex(t => t.id === id);
    if (index === -1) {
      throw new Error(`Task with id ${id} not found`);
    }

    this.tasks.splice(index, 1);
    this.persist();
    return true;
  }

  /**
   * 标记任务完成
   */
  completeTask(id) {
    return this.updateTask(id, { status: TaskStatus.COMPLETED });
  }

  /**
   * 标记任务未完成
   */
  uncompleteTask(id) {
    return this.updateTask(id, { status: TaskStatus.PENDING });
  }

  /**
   * 过滤任务
   */
  filterTasks(filters = {}) {
    let result = [...this.tasks];

    // 按状态过滤
    if (filters.status) {
      result = result.filter(t => t.status === filters.status);
    }

    // 按优先级过滤
    if (filters.priority) {
      result = result.filter(t => t.priority === filters.priority);
    }

    // 按分类过滤
    if (filters.categoryId) {
      result = result.filter(t => t.categoryId === filters.categoryId);
    }

    // 按关键词搜索
    if (filters.keyword) {
      const keyword = filters.keyword.toLowerCase();
      result = result.filter(t => 
        t.title.toLowerCase().includes(keyword) ||
        t.description.toLowerCase().includes(keyword)
      );
    }

    // 按截止日期过滤（即将到期）
    if (filters.overdue) {
      const now = new Date();
      result = result.filter(t => 
        t.dueDate && new Date(t.dueDate) < now && t.status !== TaskStatus.COMPLETED
      );
    }

    return result.map(task => Task.fromJSON(task));
  }

  /**
   * 排序任务
   */
  sortTasks(tasks, sortBy = 'createdAt', order = 'desc') {
    return [...tasks].sort((a, b) => {
      let valueA = a[sortBy];
      let valueB = b[sortBy];

      // 处理日期
      if (valueA instanceof Date || typeof valueA === 'string') {
        valueA = new Date(valueA).getTime();
        valueB = new Date(valueB).getTime();
      }

      // 处理优先级
      if (sortBy === 'priority') {
        const priorityOrder = { high: 3, medium: 2, low: 1 };
        valueA = priorityOrder[valueA];
        valueB = priorityOrder[valueB];
      }

      if (order === 'asc') {
        return valueA - valueB;
      } else {
        return valueB - valueA;
      }
    });
  }

  /**
   * 统计数据
   */
  getStatistics() {
    const total = this.tasks.length;
    const completed = this.tasks.filter(t => t.status === TaskStatus.COMPLETED).length;
    const pending = this.tasks.filter(t => t.status === TaskStatus.PENDING).length;
    const inProgress = this.tasks.filter(t => t.status === TaskStatus.IN_PROGRESS).length;

    const highPriority = this.tasks.filter(
      t => t.priority === TaskPriority.HIGH && t.status !== TaskStatus.COMPLETED
    ).length;

    return {
      total,
      completed,
      pending,
      inProgress,
      highPriority,
      completionRate: total > 0 ? Math.round((completed / total) * 100) : 0
    };
  }

  /**
   * 持久化数据
   */
  persist() {
    storageService.saveTasks(this.tasks);
  }

  /**
   * 清空所有任务
   */
  clearAll() {
    this.tasks = [];
    this.persist();
  }
}

export const taskService = new TaskService();
