            <label for="task-due-date">截止日期</label>
            <input 
              type="date" 
              id="task-due-date" 
              name="dueDate"
            />
          </div>
        </div>

        <div class="form-group">
          <label for="task-tags">标签（用逗号分隔）</label>
          <input 
            type="text" 
            id="task-tags" 
            name="tags"
            placeholder="工作，紧急，学习"
          />
        </div>

        <div class="form-actions">
          <button type="submit" class="btn btn-primary">添加任务</button>
          <button type="reset" class="btn btn-secondary">重置</button>
        </div>
      </form>
    `;

    this.bindEvents();
  }

  bindEvents() {
    const form = this.container.querySelector('#task-form');

    form.addEventListener('submit', (e) => {
      e.preventDefault();
      this.handleSubmit(e);
    });

    form.addEventListener('reset', () => {
      setTimeout(() => {
        this.container.querySelector('#task-title').focus();
      }, 0);
    });
  }

  handleSubmit(e) {
    const formData = new FormData(e.target);

    const taskData = {
      title: formData.get('title'),
      description: formData.get('description'),
      priority: formData.get('priority'),
      dueDate: formData.get('dueDate') || null,
      tags: formData.get('tags')
        ? formData.get('tags').split(',').map(tag => tag.trim()).filter(Boolean)
        : []
    };

    const task = this.onSubmit(taskData);
    this.reset();

    return task;
  }

  reset() {
    const form = this.container.querySelector('#task-form');
    form.reset();
    this.container.querySelector('#task-title').focus();
  }
}
